      "properties": {
        "uid": "urn:x-noaa:sensor:wsr88d",
        "featureType": "http://www.w3.org/ns/sosa/Sensor",
        "name": "NEXRAD Weather Surveillance Radar (WSR-88D)",
        "description": "The NEXRAD radar detects precipitation and atmospheric movement or wind.It incorporates a number of improvements over the radar systems that were previously in use. The new system provided Doppler velocity, improving tornado prediction ability by detecting rotation present within the storm at different scan angles. It provided improved resolution and sensitivity, enabling operators to see features such as cold fronts, thunderstorm gust fronts, and mesoscale to even storm scale features of thunderstorms that had never been visible on radar. The NEXRAD radars also provided volumetric scans of the atmosphere allowing operators to examine the vertical structure of storms and could act as wind profilers by providing detailed wind information for several kilometers above the radar site. The radars also had a much increased range allowing detection of weather events at much greater distances from the radar site.",
        "validTime": [
          "1988-01-01T00:00:00Z",
          "now"
        ]
      }
    },
    {
      "type": "Feature",
      "id": "17aejfsdp8t0",
      "geometry": null,
      "properties": {
        "uid": "urn:mrn:iala:systems:ais",
        "featureType": "http://www.w3.org/ns/sosa/System",
        "name": "AIS Monitoring System",
        "description": "The automatic identification system (AIS) is an automatic tracking system that uses transceivers on ships and is used by vessel traffic services (VTS). When satellites are used to receive AIS signatures, the term Satellite-AIS (S-AIS) is used. AIS information supplements marine radar, which continues to be the primary method of collision avoidance for water transport.[citation needed] Although technically and operationally distinct, the ADS-B system is analogous to AIS and performs a similar function for aircraft.",
        "validTime": [
          "2002-06-01T00:00:00Z",
          "now"
        ]
      }
    },
    {
      "type": "Feature",
      "id": "16es9scutsug",
      "geometry": null,
      "properties": {
        "uid": "urn:x-philips:sensor:8718696769881",
        "featureType": "http://www.w3.org/ns/sosa/Sensor",
        "name": "Philips Hue Motion Sensor",
        "description": "The battery-powered Hue motion sensor can be easily installed anywhere in your home and used to trigger your smart lights with movement. "
      }
    },
    {
      "type": "Feature",
      "id": "16ku7dd2kl3g",
      "geometry": null,
      "properties": {
        "uid": "urn:x-vectornav:sensor:vn200",
        "featureType": "http://www.w3.org/ns/sosa/Sensor",
        "name": "VectorNav VN-200 GNSS/INS (Rugged)",
        "description": "The VN-200 is a miniature, high performance GNSS-Aided Inertial Navigation System (GNSS/INS) that combines 3-axis gyros, accelerometers and magnetometers, a high-sensitivity GNSS receiver, and advanced Kalman filtering algorithms to provide optimal estimates of position, velocity, and attitude."
      }
    },
    {
      "type": "Feature",
      "id": "16ub9jcenh40",
      "geometry": null,
      "properties": {
        "uid": "urn:x-gill:sensor:windmaster",
        "featureType": "http://www.w3.org/ns/sosa/Sensor",
        "name": "Gill WindMaster 3-Axis Ultrasonic Anemometer",
        "description": "The Gill WindMaster is a precision anemometer offering three-axis wind measurement data. This instrument will monitor wind speeds of 0-50m/s and provides sonic temperature, speed of sound and U, V & W vector outputs at 20Hz (32Hz optional). This anemometer is of aluminium/carbon fibre construction and is ideal for the understanding of turbulent flows, surface energy balance and scalar fluxes. Each WindMaster can be calibrated with an optional Gill wind tunnel test to provide optimum performance. This 3D sonic anemometer is ideally suited to the measurement of air turbulence around bridges, buildings, wind turbine sites, building ventilation control systems, meteorological and flux measurement sites."
      }
    },
    {
      "type": "Feature",
      "id": "174bnpteip8g",
      "geometry": null,
      "properties": {
        "uid": "urn:x-lasertech:lrf:TP360R:v2",
        "featureType": "http://www.w3.org/ns/sosa/Sensor",
        "name": "Trupulse 360°R rugged Laser Range Finder",
        "description": "The TruPulse® 360°R laser rangefinder measures distance, inclination angles and azimuth with high accuracy and target acquisition. This model offers a horizontally hand-held waterproof rugged design for the harshest environments.",
        "validTime": [
          "2015-03-05T00:00:00Z",
          "now"
        ]
      }
    },
    {
      "type": "Feature",
      "id": "16er5q6mtta0",
      "geometry": null,
      "properties": {
        "uid": "urn:x-vaisala:sensor:ptb210",
        "featureType": "http://www.w3.org/ns/sosa/Sensor",
        "name": "Vaisala PTB210 Digital Barometer",
        "description": "PTB210 is ideal for outdoor installations and harsh environments. PTB210 is designed to operate in a wide temperature range, and the electronics housing provides IP65 (NEMA 4) standardized protection against sprayed water."
      }
    },
    {
      "type": "Feature",
      "id": "16hqnp5rn1b0",
      "geometry": null,
      "properties": {
        "uid": "urn:x-usgs:environment:survey:water",
        "featureType": "http://www.w3.org/ns/sosa/Procedure",
        "name": "USGS Water Sampling Procedure",
        "description": "Methodology for collecting water samples that are later analyzed in a laboratory."
      }
    },
    {
      "type": "Feature",
      "id": "17d9br79gtkg",
      "geometry": null,
      "properties": {
        "uid": "urn:x-seabird:sensor:sbe37-smp-odo",
        "featureType": "http://www.w3.org/ns/sosa/Sensor",
        "name": "Seabird SBE37 CTD/Oxygen Sensor",
        "description": "The SBE 37-SM/SMP/SMP-ODO MicroCAT is a high-accuracy conductivity and temperature (pressure optional) recorder with RS-232 or RS-485 interface, internal batteries, data storage, optional pump, and optional optical dissolved oxygen sensor. The MicroCAT is designed for moorings or other long-duration, fixed-site deployments for fully autonomous applications."
      }
    },
    {
      "type": "Feature",
      "id": "17l9f7v5glng",
      "geometry": null,
      "properties": {
        "uid": "urn:x-aanderaa:sensor:ox4831",
        "featureType": "http://www.w3.org/ns/sosa/Sensor",
        "name": "Aanderaa Oxygen Optode 4831",
        "description": "The Oxygen Optode 4831 is a compact fully integrated sensor for measuring O2 concentration and temperature."
      }
    },
    {
      "type": "Feature",
      "id": "17ial4l8s1o0",
      "geometry": null,
      "properties": {
        "uid": "urn:x-airbus:sat:astroterra",
        "featureType": "http://www.w3.org/ns/sosa/Platform",
        "name": "SPOT 6/7 AstroTerra EO Platform",
        "description": "In 2008, Spot Image of Toulouse, France, and partners (EADS Astrium) started an initiative to build a new commercial SPOT mission series, referred to as SPOT-6/7, to continue sustainable wide-swath high-resolution observation services as currently provided by the SPOT-5 mission. The spacecraft features CMGs (Control Moment Gyroscopes) instead of reaction wheels to improve pointing manoeuvrability. The satellite's in-orbit design life was 10 years."
      }
    },
    {
      "type": "Feature",
      "id": "160on14pmhog",
      "geometry": null,
      "properties": {
        "uid": "urn:x-noaa:forecast:gfs:v16.3",
        "featureType": "http://www.w3.org/ns/sosa/System",
        "name": "Global Forecast System (GFS)",
        "description": "The Global Forecast System (GFS) is a global weather forecast model developed at the National Centers for Environmental Prediction (NCEP). It generates data for dozens of atmospheric and land-soil variables, including temperatures, winds, precipitation, soil moisture, and atmospheric ozone concentration. The system couples four separate models (atmosphere, ocean model, land/soil model, and sea ice) that work together to accurately depict weather conditions. The model is constantly evolving, and regularly adjusted to improve performance and forecast accuracy.",
        "validTime": [
          "2022-11-29T00:00:00Z",
          "now"
        ]
      }
    },
    {
      "type": "Feature",
      "id": "176sl87rk5p0",
      "geometry": null,
      "properties": {
        "uid": "urn:x-saildrone:platform:explorer",
        "featureType": "http://www.w3.org/ns/sosa/Platform",
        "name": "Saildrone Explorer",
        "description": "The Saildrone Explorer is a 23-foot (7 m) vehicle powered\nby wind and solar energy capable of extreme-duration\nmissions over 12 months in the open ocean, while\nproducing a minimal carbon footprint. Sailing at an\naverage speed up to three knots, the Explorer carries a\nsuite of scientific sensors for the collection of ocean data."
      }
    },
    {
      "type": "Feature",
      "id": "16pvf1caslr0",
      "geometry": null,
      "properties": {
        "uid": "urn:x-davis:station:vantagepro2",
        "featureType": "http://www.w3.org/ns/sosa/Sensor",
        "name": "Davis Vantage Pro2 Weather Station",
        "description": "An industrial-grade weather station engineered to handle the harshest environments and deliver data with scientific precision, year after year. The Vantage Pro2 and Vantage Pro2 Plus offer the professional weather observer or serious weather enthusiast robust performance with a wide range of options and sensors."
      }
    },
    {
      "type": "Feature",
      "id": "17leno4tklvg",
      "geometry": null,
      "properties": {
        "uid": "urn:x-nsw:environment:survey:birds",
        "featureType": "http://www.w3.org/ns/sosa/Procedure",
        "name": "Bird Survey - Baseline Method",
        "description": "The Baseline method is based on setting up a single line at each site called a transect. Birds can be identified either visually, or by their calls. This method involves identifying all the birds you see or hear while standing at a series of points along a transect (a straight line through the site)."
      }
